// Parse la sortie JSON de l'agent (tolérant aux ``` et au texte parasite)
const raw = $json.output ?? $json.text ?? '';
let parsed;
try {
  let s = String(raw).trim();
  s = s.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  // récupère le 1er objet { ... } si du texte entoure le JSON
  const i = s.indexOf('{'); const j = s.lastIndexOf('}');
  if (i !== -1 && j !== -1) s = s.slice(i, j + 1);
  parsed = JSON.parse(s);
} catch (e) {
  parsed = { reply: String(raw), status: 'collecting' };
}
if (!parsed.reply)  parsed.reply  = String(raw);
if (!parsed.status) parsed.status = 'collecting';
return [{ json: parsed }];

// Données collectées par l'agent
const villeDepart  = $json.villeDepart || '';
const villeArrivee = $json.villeArrivee || '';
const dateDepart   = $json.dateDepart || '';
const nbPassagers  = Number($json.nbPassagers || 0);
const allerRetour  = !!$json.allerRetour;
const guideDays      = Number($json.guideDays || 0);
const nuitsChauffeur = Number($json.nuitsChauffeur || 0);
const peagesEuros    = Number($json.peagesEuros || 0);
const prenom = $json.prenom || '';
const nom    = $json.nom || '';
const email  = $json.email || '';
const telephone = $json.telephone || '';

// 1) Distance routière
async function geocode(ville) {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://nominatim.openstreetmap.org/search',
    qs: { q: ville, format: 'json', limit: 1 },
    headers: { 'User-Agent': 'Neotravel-Chat/1.0 contact@neotravel.fr' },
    json: true,
  });
  if (!data || !data.length) throw new Error('Ville introuvable : ' + ville);
  return { lat: parseFloat(data[0].lat), lon: parseFloat(data[0].lon) };
}
const c1 = await geocode(villeDepart);
const c2 = await geocode(villeArrivee);
const osrm = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://router.project-osrm.org/route/v1/driving/' + c1.lon + ',' + c1.lat + ';' + c2.lon + ',' + c2.lat,
  qs: { overview: 'false' },
  json: true,
});
const km = Math.round(osrm.routes[0].distance / 1000);

// 2) Devis
const escalade = nbPassagers > 85;
let prixHT = null, tva = null, prixTTC = null;
if (!escalade) {
  const grille = [[10,250],[20,250],[30,250],[40,320],[50,350],[60,390],[70,430],[80,500],[90,540],[100,580],[110,620],[120,660],[130,700],[140,740],[150,780],[160,820],[170,860],[180,900]];
  let prixBase;
  if (km <= 180) { const p = grille.find(([s]) => km <= s); prixBase = p ? p[1] : 900; }
  else { prixBase = km * 2 * 2.5; }
  if (allerRetour) prixBase *= 2;
  const mois = new Date(dateDepart).getMonth() + 1;
  const sMap = [{m:[11,1,2,8],c:-7},{m:[12,10,9],c:0},{m:[3,4,7],c:10},{m:[5,6],c:15}];
  let cS = 0; for (const x of sMap) { if (x.m.includes(mois)) { cS = x.c; break; } }
  const h = (new Date(dateDepart) - new Date()) / 3600000;
  let cU; if (h < 24) cU = 10; else if (h < 72) cU = 5; else if (h <= 2160) cU = -5; else cU = -10;
  let cC; if (nbPassagers <= 19) cC = -5; else if (nbPassagers <= 53) cC = 0; else if (nbPassagers <= 63) cC = 15; else if (nbPassagers <= 67) cC = 20; else cC = 40;
  let p = prixBase * (1 + cS/100) * (1 + cU/100) * (1 + cC/100);
  p += (guideDays*80) + (nuitsChauffeur*120) + peagesEuros;
  prixHT  = Math.round(p * 1.15 * 100) / 100;
  tva     = Math.round(prixHT * 0.10 * 100) / 100;
  prixTTC = Math.round(prixHT * 1.10 * 100) / 100;
}

// 3) HTML de l'email
const typeTrajet = allerRetour ? 'Aller-retour' : 'Aller simple';
let emailHtml = '';

if (escalade) {
  emailHtml = `
