            <td style="padding:14px 12px; border-bottom:1px solid #E2E8F0; text-align:right; color:#0A2240;"><b>${villeArrivee}</b></td>
          </tr>
          <tr>
            <td style="padding:14px 12px; border-bottom:1px solid #E2E8F0; color:#64748B;">Distance</td>
            <td style="padding:14px 12px; border-bottom:1px solid #E2E8F0; text-align:right; font-weight:bold;">${km} km</td>
          </tr>
          <tr>
            <td style="padding:14px 12px; border-bottom:1px solid #E2E8F0; color:#64748B;">Date</td>
