            <td style="padding:14px 12px; border-bottom:1px solid #E2E8F0; text-align:right; font-weight:bold;">${nbPassagers}</td>
          </tr>
          <tr>
            <td style="padding:14px 12px; color:#64748B;">Type de trajet</td>
            <td style="padding:14px 12px; text-align:right; font-weight:bold;">${typeTrajet}</td>
          </tr>
        </table>

        <div style="margin-top:35px; padding:25px; background:#F8FAFC; border:1px solid #E2E8F0; border-radius:10px; text-align:center;">
          <h3 style="margin-top:0; color:#64748B; font-size:14px; text-transform:uppercase; letter-spacing:1px;">Montant estimé</h3>
          <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:10px; font-size:14px; color:#64748B;">
            <tr>
              <td align="left">Prix HT :</td>
              <td align="right" style="font-weight:bold; color:#333333;">${prixHT} €</td>
            </tr>
            <tr>
              <td align="left">TVA :</td>
              <td align="right" style="font-weight:bold; color:#333333;">${tva} €</td>
            </tr>
          </table>
          <div style="font-size:36px; color:#0A2240; font-weight:bold; margin-top:15px; border-top:1px dashed #E2E8F0; padding-top:15px;">
            ${prixTTC} € <span style="font-size:16px; font-weight:normal; color:#64748B;">TTC</span>
          </div>
        </div>

        <p style="margin-top:35px; font-weight:bold; color:#0A2240;">Ce tarif comprend :</p>
        <ul style="padding-left:5px; list-style:none; line-height:2;">
          <li>✔ Chauffeur professionnel certifié</li>
          <li>✔ Carburant et kilomètres inclus</li>
          <li>✔ Péages (si applicables et renseignés)</li>
          <li>✔ Assurance passagers intégrée</li>
          <li>✔ Assistance NeoTravel 24h/7j</li>
        </ul>

        <div style="text-align:center; margin-top:40px; margin-bottom:10px;">
          <a href="https://neotravel.fr" target="_blank" style="background:#8AA84B; color:white; padding:16px 35px; text-decoration:none; border-radius:8px; display:inline-block; font-weight:bold; font-size:16px; box-shadow:0 4px 12px rgba(138,168,75,0.25);">📞 Confirmer ou modifier mon devis</a>
        </div>
        <p style="margin-top:40px; color:#94A3B8; font-size:13px; text-align:center; line-height:1.4;">Ce devis est fourni à titre indicatif. Un conseiller dédié examinera votre dossier et reprendra contact avec vous dans les meilleurs délais, du lundi au vendredi de 9h à 18h, pour valider définitivement la réservation de votre véhicule.</p>
      </td>
    </tr>
  </table>
  </td>
  </tr>
  </table>
  </body>
  </html>`;
}

return [{ json: { prenom, nom, email, telephone, villeDepart, villeArrivee, dateDepart, nbPassagers, allerRetour, km, prixHT, tva, prixTTC, escalade, emailHtml } }];

// === Préparer Email Clarification (demande incomplète) ===
// Données collectées par l'agent
const villeDepart  = $json.villeDepart || '';
const villeArrivee = $json.villeArrivee || '';
const dateDepart   = $json.dateDepart || '';
const nbPassagers  = Number($json.nbPassagers || 0);
const prenom = $json.prenom || '';
const nom    = $json.nom || '';
const email  = $json.email || '';
const telephone = $json.telephone || '';

// On recalcule nous-mêmes les champs obligatoires manquants
const manquants = [];
if (!villeDepart)  manquants.push('Votre ville de départ');
if (!villeArrivee) manquants.push("Votre ville d'arrivée (destination)");
if (!dateDepart)   manquants.push('Votre date de départ');
if (!nbPassagers)  manquants.push('Le nombre de passagers');

const listeManquants = manquants.map(m => `<li>➡️ ${m}</li>`).join('');

// Lien de retour vers le chat / la page devis (À REMPLACER par ton URL réelle)
